print("\n" + "="*50)
print("自动识别 - 高频地点 TOP10")
print("-"*50)
for i, (name, cnt) in enumerate(top_places, 1):
    print(f"{i:2d}. {name:<25} 出现次数：{cnt}")

"""#### (c) TF-IDF [4 marks]

In this question you will calculate the term frequency-inverse document frequency (TF-IDF) vector representations of every story in the corpus.

Begin by constructing a list containing the vocabulary of the the corpus.

Construct a function `tf()` that takes as input a tokenised document (story), and outputs a log-adjusted term frequency (TF) vector.

**Note**: The log-adjusted term frequency of a word $w$ in a document $d$ is:

$$
\text{tf}_{w,d} =
\begin{cases}
1 + \log_{10}\text{count}(w, d) \quad & \text{if  count}(w,d)>0  \\
0   & \text{otherwise}
\end{cases}
$$




Construct a function `idf()` that takes as input the vocabulary list and the entire corpus, and outputs a smoothed inverse document frequency (IDF) vector.

**Note**: the smoothed inverse document frequency of a word $w$ is:

$$
\text{idf}_w = \log_{10}\left(\frac{N}{\text{df}_w+1}\right)+1
$$
where $\text{df}_w$ counts the number of documents a word $w$ appears in and $N$ is the total number of documents.

Use these two functions to compute a TF-IDF matrix where each row is the TF-IDF of a particular story in the corpus.
"""

import math
import re
import string
from collections import Counter, defaultdict

# ===================== 1. 通用预处理函数（对接你的holmes语料） =====================
def preprocess_and_tokenize(text):
    """复用你原有的预处理逻辑，保证数据格式统一"""
    text = text.lower()
    text = text.translate(str.maketrans('', '', string.punctuation))
    text = re.sub(r'\d+', '', text)
    text = re.sub(r'\s+', ' ', text).strip()
    tokens = text.split()
    tokens = [token for token in tokens if len(token) > 1]
    return tokens

# ===================== 2. 构建语料库词汇表（严格按题目要求） =====================
def build_vocabulary(corpus):
    """
    题目要求：Construct a list containing the vocabulary of the corpus
    :param corpus: 分词后的语料库（tokenised_stories）
    :return: 排序后的词汇表列表、词-索引映射
    """
    vocab = set()
    for doc in corpus:
        vocab.update(doc)
    vocab = sorted(list(vocab))  # 固定词汇表顺序，保证向量维度一致
    word_to_idx = {word: i for i, word in enumerate(vocab)}
    return vocab, word_to_idx

# ===================== 3. 实现题目指定的 tf() 函数 =====================
def tf(tokenised_doc, vocab, word_to_idx):
    """
    题目要求：log-adjusted TF 函数
    公式：tf(w,d) = 1+log10(count) if count>0 else 0
    :param tokenised_doc: 单个分词文档
    :param vocab: 全局词汇表
    :param word_to_idx: 词-索引映射
    :return: log-adjusted TF 向量
    """
    count = Counter(tokenised_doc)
    tf_vec = [0.0] * len(vocab)  # 向量长度=词汇表大小

    for word, cnt in count.items():
        if word in word_to_idx:
            idx = word_to_idx[word]
            tf_vec[idx] = 1 + math.log10(cnt) if cnt > 0 else 0.0
    return tf_vec

# ===================== 4. 实现题目指定的 idf() 函数 =====================
def idf(vocab, word_to_idx, corpus):
    """
    题目要求：smoothed IDF 函数
    公式：idf(w) = log10(N/(dfw + 1)) + 1
    :param vocab: 全局词汇表
    :param word_to_idx: 词-索引映射
    :param corpus: 整个分词语料库
    :return: smoothed IDF 向量
    """
    N = len(corpus)  # 总文档数
    df = [0] * len(vocab)  # 文档频率初始化

    # 统计每个词出现在多少个文档中
    for doc in corpus:
        unique_words = set(doc)
        for word in unique_words:
            if word in word_to_idx:
                df[word_to_idx[word]] += 1

    # 计算平滑IDF
    idf_vec = []
    for dfw in df:
        idf_val = math.log10(N / (dfw + 1)) + 1  # 严格按题目公式
        idf_vec.append(idf_val)
    return idf_vec

# ===================== 5. 计算 TF-IDF 矩阵（题目最终要求） =====================
def compute_tfidf_matrix(corpus, vocab, word_to_idx):
    """
    题目要求：每行对应一个故事的 TF-IDF 向量
    :return: TF-IDF 矩阵、全局IDF向量
    """
    # 计算全局IDF（仅需一次）
    global_idf = idf(vocab, word_to_idx, corpus)
    tfidf_matrix = []

    # 逐文档计算TF并与IDF相乘
